class Solution:
    def minJumps(self, treeLevelOrder: str, frm: str, to: str) -> int:
        # 1. 拆分并去空格
        nodes = treeLevelOrder.split(',')
        nodes = [n.strip() for n in nodes]

        # 2. 定位两个节点的索引
        pos_frm = pos_to = -1
        for i, node in enumerate(nodes):
            if node == frm: pos_frm = i
            if node == to: pos_to = i

        if pos_frm == -1 or pos_to == -1:
            return -1                     # 节点不存在

        # 3. 深度计算：从索引上溯到根
        def depth(pos: int) -> int:
            d = 0
            while pos > 0:
                pos = (pos - 1) // 2      # 父节点索引
                d += 1
            return d

        d1, d2 = depth(pos_frm), depth(pos_to)
        orig_d1, orig_d2 = d1, d2

        # 4. 上溯到同一深度
        while d1 > d2:
            pos_frm = (pos_frm - 1) // 2
            d1 -= 1
        while d2 > d1:
            pos_to = (pos_to - 1) // 2
            d2 -= 1

        # 5. 同时上溯找 LCA
        while pos_frm != pos_to:
            pos_frm = (pos_frm - 1) // 2
            pos_to = (pos_to - 1) // 2

        d_lca = depth(pos_frm)
        return orig_d1 + orig_d2 - 2 * d_lca
```

```java
class Solution {
    public int minJumps(String treeLevelOrder, String frm, String to) {
        // 1. 拆分
        String[] nodes = treeLevelOrder.split(",");
        for (int i = 0; i < nodes.length; i++)
            nodes[i] = nodes[i].trim();

        // 2. 定位
        int posFrm = -1, posTo = -1;
        for (int i = 0; i < nodes.length; i++) {
            if (nodes[i].equals(frm)) posFrm = i;
            if (nodes[i].equals(to)) posTo = i;
        }
        if (posFrm == -1 || posTo == -1) return -1;

        // 3. 深度
        int d1 = depth(posFrm), d2 = depth(posTo);
        int origD1 = d1, origD2 = d2;

        // 4. 同一深度
        while (d1 > d2) { posFrm = (posFrm - 1) / 2; d1--; }
        while (d2 > d1) { posTo = (posTo - 1) / 2; d2--; }

        // 5. LCA
        while (posFrm != posTo) {
            posFrm = (posFrm - 1) / 2;
            posTo = (posTo - 1) / 2;
        }

        return origD1 + origD2 - 2 * depth(posFrm);
    }

    private int depth(int pos) {
        int d = 0;
        while (pos > 0) { pos = (pos - 1) / 2; d++; }
        return d;
    }
}
