#include <string>
#include <vector>
using namespace std;

class Solution {
public:
    int minJumps(string treeLevelOrder, string frm, string to) {
        // 1. 按逗号拆分并去空格
        vector<string> nodes;
        size_t start = 0;
        while (start <= treeLevelOrder.size()) {
            size_t comma = treeLevelOrder.find(',', start);
            string node = (comma == string::npos)
                ? treeLevelOrder.substr(start)
                : treeLevelOrder.substr(start, comma - start);
            size_t s = node.find_first_not_of(' ');
            if (s != string::npos) {
                size_t e = node.find_last_not_of(' ');
                node = node.substr(s, e - s + 1);
            }
            nodes.push_back(node);
            if (comma == string::npos) break;
            start = comma + 1;
        }

        // 2. 定位
        int posFrm = -1, posTo = -1;
        for (int i = 0; i < (int)nodes.size(); i++) {
            if (nodes[i] == frm) posFrm = i;
            if (nodes[i] == to) posTo = i;
        }
        if (posFrm == -1 || posTo == -1) return -1;

        // 3. 深度函数
        auto depth = [](int pos) {
            int d = 0;
            while (pos > 0) { pos = (pos - 1) / 2; d++; }
            return d;
        };

        int d1 = depth(posFrm), d2 = depth(posTo);
        int origD1 = d1, origD2 = d2;

        // 4. 同一深度
        while (d1 > d2) { posFrm = (posFrm - 1) / 2; d1--; }
        while (d2 > d1) { posTo = (posTo - 1) / 2; d2--; }

        // 5. LCA
        while (posFrm != posTo) {
            posFrm = (posFrm - 1) / 2;
            posTo = (posTo - 1) / 2;
        }

        return origD1 + origD2 - 2 * depth(posFrm);
    }
};
