var minJumps = function(treeLevelOrder, frm, to) {
    // 1. 拆分并去空格
    const nodes = treeLevelOrder.split(',').map(s => s.trim());

    // 2. 定位
    let posFrm = -1, posTo = -1;
    for (let i = 0; i < nodes.length; i++) {
        if (nodes[i] === frm) posFrm = i;
        if (nodes[i] === to) posTo = i;
    }
    if (posFrm === -1 || posTo === -1) return -1;

    // 3. 深度
    const depth = (pos) => {
        let d = 0;
        while (pos > 0) { pos = Math.floor((pos - 1) / 2); d++; }
        return d;
    };

    let d1 = depth(posFrm), d2 = depth(posTo);
    const origD1 = d1, origD2 = d2;

    // 4. 同一深度
    while (d1 > d2) { posFrm = Math.floor((posFrm - 1) / 2); d1--; }
    while (d2 > d1) { posTo = Math.floor((posTo - 1) / 2); d2--; }

    // 5. LCA
    while (posFrm !== posTo) {
        posFrm = Math.floor((posFrm - 1) / 2);
        posTo = Math.floor((posTo - 1) / 2);
    }

    return origD1 + origD2 - 2 * depth(posFrm);
};
