#include <string.h>
#include <stdlib.h>
#include <stdio.h>

// 计算从索引出发的深度
static int calcDepth(int pos) {
    int d = 0;
    while (pos > 0) { pos = (pos - 1) / 2; d++; }
    return d;
}

int minJumps(char* treeLevelOrder, char* frm, char* to) {
    // 1. 定位 frm 和 to 的索引（边遍历边定位，避免存储全部分片）
    int posFrm = -1, posTo = -1;
    int idx = 0;
    char* tok = strtok(treeLevelOrder, ",");
    while (tok) {
        // 去前导空格
        while (*tok == ' ') tok++;
        // 去尾随空格
        int tlen = (int)strlen(tok);
        while (tlen > 0 && tok[tlen - 1] == ' ') { tok[--tlen] = '\0'; }

        if (strcmp(tok, frm) == 0) posFrm = idx;
        if (strcmp(tok, to) == 0) posTo = idx;
        idx++;
        tok = strtok(NULL, ",");
    }

    if (posFrm == -1 || posTo == -1) return -1;

    // 2. 计算深度
    int d1 = calcDepth(posFrm), d2 = calcDepth(posTo);
    int origD1 = d1, origD2 = d2;

    // 3. 同一深度
    while (d1 > d2) { posFrm = (posFrm - 1) / 2; d1--; }
    while (d2 > d1) { posTo = (posTo - 1) / 2; d2--; }

    // 4. LCA
    while (posFrm != posTo) {
        posFrm = (posFrm - 1) / 2;
        posTo = (posTo - 1) / 2;
    }

    return origD1 + origD2 - 2 * calcDepth(posFrm);
}
